package equivalent;

import metadata.BehavioralDifference;
import metadata.DifferenceType;

import org.junit.jupiter.api.Tag;
import org.junit.jupiter.api.Test;

import static equivalent.ClonePairGenericInvocationTestSupport.*;

@Tag("timeout")
class ClonePair5323DifferenceFindingTest {

    private final ClonePair5323 subject = new ClonePair5323();

    /**
     * Generated by Codex (GPT-5.5).
     * Difference type: no_termination.
     * Difference manifestation: the methods differ in whether they terminate.
     */
    @Test
    @BehavioralDifference(DifferenceType.NO_TERMINATION)
    void methodsDisagreeOnEmptyPatternAtMinimumIndex() {
        Object[] inputs = new Object[]{"", "", Integer.MIN_VALUE};
        InvocationOutcome method1Outcome = captureWithTimeout(values -> subject.method1((String) values[0], (String) values[1], ((Integer) values[2]).intValue()), 200L, inputs);
        InvocationOutcome method2Outcome = captureWithTimeout(values -> subject.method2((String) values[0], (String) values[1], ((Integer) values[2]).intValue()), 200L, inputs);

        assertCoreOutcome(
            method1Outcome,
            "OK",
            "Integer(-1)",
            null,
            "java.lang.Object[][String(),String(),Integer(-2147483648)]",
            "java.lang.Object[][String(),String(),Integer(-2147483648)]"
        );
        assertCoreOutcome(
            method2Outcome,
            "TIMEOUT",
            null,
            null,
            "java.lang.Object[][String(),String(),Integer(-2147483648)]",
            "java.lang.Object[][String(),String(),Integer(-2147483648)]"
        );
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stdout", "", method2Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertTextEquals("stderr", "", method2Outcome.stderr);
    }
}
